using System.Text.RegularExpressions;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.Text;

namespace VisualRelay.Guards;

/// <summary>
/// Pure matcher that flags sync-over-async deadlock patterns in C# test sources.
/// A blocking <c>.Result</c>, <c>.GetAwaiter().GetResult()</c>, or <c>.Wait()</c>
/// inside a <c>[Fact]</c>/<c>[AvaloniaFact]</c>/<c>[Theory]</c>/<c>[AvaloniaTheory]</c>
/// test method body deadlocks the single-threaded Avalonia headless dispatcher —
/// the continuation needs the same thread that is blocked. This guard catches
/// the pattern at build time (fast, named) instead of via a 60 s blame-hang.
///
/// An inline <c>// vr-allow-sync-over-async: &lt;reason&gt;</c> on the violation's
/// line suppresses it; a bare marker with no reason does not. The matcher
/// self-exempts <c>SyncOverAsyncGuard.cs</c>, <c>SyncOverAsyncGuardTests.cs</c>,
/// <c>RealSleepGuard.cs</c>, <c>RealSleepGuardTests.cs</c>, and
/// <c>WindowsLauncherTests.cs</c> by filename.
/// No I/O, no git — callers supply the (path, source) pairs.
/// </summary>
public static class SyncOverAsyncGuard
{
    /// <summary>Describes a single sync-over-async violation (1-based <paramref name="Line"/>).</summary>
    public sealed record Violation(string Path, int Line, string Snippet, string Reason);

    /// <summary>A same-line suppression — only valid with a non-empty reason after the colon.</summary>
    private static readonly Regex AllowMarkerPattern =
        new(@"//\s*vr-allow-sync-over-async:\s*\S", RegexOptions.Compiled);

    /// <summary>Filenames whose own bodies legitimately contain sync-over-async fixtures or patterns.</summary>
    private static readonly string[] SelfExemptFileNames = [
        "SyncOverAsyncGuard.cs",
        "SyncOverAsyncGuardTests.cs",
        "RealSleepGuard.cs",
        "RealSleepGuardTests.cs",
        "WindowsLauncherTests.cs",
    ];

    private static readonly CSharpParseOptions ParseOptions = new(LanguageVersion.Latest);

    /// <summary>
    /// Returns every sync-over-async violation across <paramref name="files"/>, ordered by
    /// path (ordinal) then line. Self-exempt files yield nothing.
    /// </summary>
    public static IReadOnlyList<Violation> FindViolations(IEnumerable<(string Path, string Source)> files)
    {
        var violations = new List<Violation>();

        foreach (var (path, source) in files)
        {
            if (SelfExemptFileNames.Contains(Path.GetFileName(path)))
                continue;

            ScanSource(path, source, violations);
        }

        violations.Sort((a, b) =>
        {
            var byPath = string.CompareOrdinal(a.Path, b.Path);
            return byPath != 0 ? byPath : a.Line.CompareTo(b.Line);
        });
        return violations;
    }

    private static void ScanSource(string path, string source, List<Violation> sink)
    {
        var tree = CSharpSyntaxTree.ParseText(source, ParseOptions);
        var text = tree.GetText();
        var root = tree.GetRoot();

        var raw = new List<Violation>();

        foreach (var method in root.DescendantNodes().OfType<MethodDeclarationSyntax>())
        {
            if (!IsTestMethod(method))
                continue;

            var body = (SyntaxNode?)method.Body ?? method.ExpressionBody;
            if (body is null)
                continue;

            // Pattern 1: .Result member access on any expression inside a test method body.
            foreach (var ma in body.DescendantNodesAndSelf().OfType<MemberAccessExpressionSyntax>())
            {
                if (ma.Name.Identifier.Text != "Result")
                    continue;

                var line = LineOf(text, ma.Name.Identifier.SpanStart);
                raw.Add(new Violation(path, line, SnippetOf(text, line),
                    "sync-over-async: .Result in [Fact]/[AvaloniaFact] test method"));
            }

            // Pattern 2: .GetAwaiter().GetResult() chain inside a test method body.
            foreach (var inv in body.DescendantNodesAndSelf().OfType<InvocationExpressionSyntax>())
            {
                if (inv.Expression is not MemberAccessExpressionSyntax outerMa
                    || outerMa.Name.Identifier.Text != "GetResult")
                    continue;

                if (outerMa.Expression is not InvocationExpressionSyntax innerInv
                    || innerInv.Expression is not MemberAccessExpressionSyntax innerMa
                    || innerMa.Name.Identifier.Text != "GetAwaiter")
                    continue;

                var line = LineOf(text, outerMa.Name.Identifier.SpanStart);
                raw.Add(new Violation(path, line, SnippetOf(text, line),
                    "sync-over-async: .GetAwaiter().GetResult() in [Fact]/[AvaloniaFact] test method"));
            }

            // Pattern 3: .Wait() / .Wait(timeout) invocation inside a test method body.
            foreach (var inv in body.DescendantNodesAndSelf().OfType<InvocationExpressionSyntax>())
            {
                if (inv.Expression is not MemberAccessExpressionSyntax ma
                    || ma.Name.Identifier.Text != "Wait")
                    continue;

                var line = LineOf(text, ma.Name.Identifier.SpanStart);
                raw.Add(new Violation(path, line, SnippetOf(text, line),
                    "sync-over-async: .Wait() in [Fact]/[AvaloniaFact] test method"));
            }
        }

        // Apply the inline allow-list, then de-duplicate per (line, reason).
        var seen = new HashSet<(int Line, string Reason)>();
        foreach (var v in raw)
        {
            if (AllowMarkerPattern.IsMatch(text.Lines[v.Line - 1].ToString()))
                continue;
            if (seen.Add((v.Line, v.Reason)))
                sink.Add(v);
        }
    }

    /// <summary>
    /// Returns true when <paramref name="method"/> carries a
    /// <c>[Fact]</c>, <c>[AvaloniaFact]</c>, <c>[Theory]</c>, or <c>[AvaloniaTheory]</c>
    /// attribute.
    /// </summary>
    private static bool IsTestMethod(MethodDeclarationSyntax method)
    {
        foreach (var attrList in method.AttributeLists)
        {
            foreach (var attr in attrList.Attributes)
            {
                var name = LastIdentifier(attr.Name);
                if (name is "Fact" or "AvaloniaFact" or "Theory" or "AvaloniaTheory")
                    return true;
            }
        }
        return false;
    }

    /// <summary>Returns the rightmost identifier of a <see cref="NameSyntax"/>.</summary>
    private static string LastIdentifier(NameSyntax name) => name switch
    {
        IdentifierNameSyntax id => id.Identifier.Text,
        QualifiedNameSyntax q => LastIdentifier(q.Right),
        AliasQualifiedNameSyntax a => LastIdentifier(a.Name),
        _ => string.Empty,
    };

    private static int LineOf(SourceText text, int position) =>
        text.Lines.GetLinePosition(position).Line + 1;

    private static string SnippetOf(SourceText text, int line)
    {
        var s = text.Lines[line - 1].ToString().Trim();
        return s.Length <= 200 ? s : s[..200];
    }
}

using VisualRelay.Guards;

namespace VisualRelay.Tests;

/// <summary>
/// The enforcing sync-over-async guard-as-test (the house idiom mirrored from
/// <see cref="RealSleepGuardTests"/>). The matcher
/// (<see cref="SyncOverAsyncGuard.FindViolations"/>) is pure: it Roslyn-parses each
/// source and flags blocking <c>.Result</c>, <c>.GetAwaiter().GetResult()</c>, or
/// <c>.Wait()</c> calls inside <c>[Fact]</c>/<c>[AvaloniaFact]</c>/<c>[Theory]</c>/
/// <c>[AvaloniaTheory]</c> test method bodies — the classic sync-over-async deadlock
/// on the single-threaded Avalonia headless dispatcher.
///
/// This file carries the matcher's behavioural facts plus the live enumeration gate.
/// It is self-exempt by filename in <see cref="SyncOverAsyncGuard"/> because it
/// contains sync-over-async fixtures; that exemption is exactly why the live gate can
/// scan the test project without tripping on these strings.
/// </summary>
public sealed class SyncOverAsyncGuardTests
{
    /// <summary>
    /// A <c>.Result</c> member access inside an <c>[AvaloniaFact]</c> test method body
    /// is reported as a sync-over-async deadlock.
    /// </summary>
    [Fact]
    public void DotResult_InAvaloniaFact_IsReported()
    {
        const string source = """
            using Xunit;
            using Avalonia.Headless.XUnit;
            class C { [AvaloniaFact] void M() { var t = GetTask(); _ = t.Result; } static Task GetTask() => Task.CompletedTask; }
            """;

        var violations = SyncOverAsyncGuard.FindViolations([("Fixtures/Deadlock.cs", source)]);

        var v = Assert.Single(violations);
        Assert.Equal("Fixtures/Deadlock.cs", v.Path);
        Assert.Contains(".Result", v.Reason);
    }

    /// <summary>
    /// A <c>.GetAwaiter().GetResult()</c> chain inside a <c>[Fact]</c> test method body
    /// is reported.
    /// </summary>
    [Fact]
    public void GetAwaiterGetResult_InFact_IsReported()
    {
        const string source = """
            using Xunit;
            class C { [Fact] void M() { GetTask().GetAwaiter().GetResult(); } static Task GetTask() => Task.CompletedTask; }
            """;

        var violations = SyncOverAsyncGuard.FindViolations([("Fixtures/GetResult.cs", source)]);

        var v = Assert.Single(violations);
        Assert.Equal("Fixtures/GetResult.cs", v.Path);
        Assert.Contains(".GetAwaiter().GetResult()", v.Reason);
    }

    /// <summary>
    /// A <c>.Wait()</c> call inside an <c>[AvaloniaFact]</c> test method body is reported.
    /// </summary>
    [Fact]
    public void Wait_InAvaloniaFact_IsReported()
    {
        const string source = """
            using Xunit;
            using Avalonia.Headless.XUnit;
            class C { [AvaloniaFact] void M() { GetTask().Wait(); } static Task GetTask() => Task.CompletedTask; }
            """;

        var violations = SyncOverAsyncGuard.FindViolations([("Fixtures/Wait.cs", source)]);

        var v = Assert.Single(violations);
        Assert.Equal("Fixtures/Wait.cs", v.Path);
        Assert.Contains(".Wait()", v.Reason);
    }

    /// <summary>
    /// The correct <c>async Task</c> with <c>await</c> pattern inside an
    /// <c>[AvaloniaFact]</c> yields zero violations — no sync-over-async, no deadlock.
    /// </summary>
    [Fact]
    public void AwaitPattern_IsClean()
    {
        const string source = """
            using Xunit;
            using Avalonia.Headless.XUnit;
            class C { [AvaloniaFact] async Task M() { await GetTask(); } static Task GetTask() => Task.CompletedTask; }
            """;

        var violations = SyncOverAsyncGuard.FindViolations([("Fixtures/Clean.cs", source)]);

        Assert.Empty(violations);
    }

    /// <summary>
    /// <c>new BackendVenv.Result(null)</c> inside a <c>[Fact]</c> is an object creation
    /// where <c>Result</c> is part of a qualified type name — not a member-access
    /// <c>.Result</c> on a Task. Not reported.
    /// </summary>
    [Fact]
    public void BackendVenvDotResult_IsNotReported()
    {
        const string source = """
            using Xunit;
            namespace VR { class BackendVenv { public record Result(string? Path); } }
            class C { [Fact] void M() { var r = new VR.BackendVenv.Result(null); } }
            """;

        var violations = SyncOverAsyncGuard.FindViolations([("Fixtures/BackendVenv.cs", source)]);

        Assert.Empty(violations);
    }

    /// <summary>
    /// A <c>.GetAwaiter().GetResult()</c> in a static helper method that is not a
    /// <c>[Fact]</c>/<c>[AvaloniaFact]</c> is not reported — the guard only scopes
    /// inside test-method bodies.
    /// </summary>
    [Fact]
    public void GetAwaiterGetResult_InStaticHelper_NotInTestMethod_IsNotReported()
    {
        const string source = """
            using Xunit;
            class C {
                static void Helper() { GetTask().GetAwaiter().GetResult(); }
                [Fact] void M() { Helper(); }
                static Task GetTask() => Task.CompletedTask;
            }
            """;

        var violations = SyncOverAsyncGuard.FindViolations([("Fixtures/Helper.cs", source)]);

        Assert.Empty(violations);
    }

    /// <summary>
    /// A <c>.Result</c> line carrying <c>// vr-allow-sync-over-async: justified</c>
    /// is suppressed — the allow-marker with a reason excuses the violation.
    /// </summary>
    [Fact]
    public void AllowMarker_WithReason_Suppresses()
    {
        const string source = """
            using Xunit;
            using Avalonia.Headless.XUnit;
            class C { [AvaloniaFact] void M() { _ = GetTask().Result; } // vr-allow-sync-over-async: justified
            static Task GetTask() => Task.CompletedTask; }
            """;

        var violations = SyncOverAsyncGuard.FindViolations([("Fixtures/Allowed.cs", source)]);

        Assert.Empty(violations);
    }

    /// <summary>
    /// A bare marker is not a valid suppression: <c>// vr-allow-sync-over-async:</c>
    /// with no reason after the colon does not excuse the violation — it is still reported.
    /// </summary>
    [Fact]
    public void BareAllowMarker_StillReported()
    {
        const string source = """
            using Xunit;
            using Avalonia.Headless.XUnit;
            class C { [AvaloniaFact] void M() { _ = GetTask().Result; } // vr-allow-sync-over-async:
            static Task GetTask() => Task.CompletedTask; }
            """;

        var violations = SyncOverAsyncGuard.FindViolations([("Fixtures/BareMarker.cs", source)]);

        Assert.NotEmpty(violations);
    }

    /// <summary>
    /// The live enforcing gate: every <c>*.cs</c> in the test project (excluding bin/obj)
    /// is free of sync-over-async deadlocks. The existing suite uses the correct async
    /// pattern, so this gate starts green and stays that way — any reintroduced
    /// sync-over-async flip the guard to a build failure.
    /// </summary>
    [Fact]
    public void AllTestProjectCsFiles_HaveNoSyncOverAsync()
    {
        var testsDir = Path.Combine(RepoSetup.Root, "tests", "VisualRelay.Tests");

        var files = Directory.EnumerateFiles(testsDir, "*.cs", SearchOption.AllDirectories)
            .Where(f => !IsBuildArtifact(f))
            .Select(f => (Path.GetRelativePath(RepoSetup.Root, f), File.ReadAllText(f)))
            .ToList();

        var violations = SyncOverAsyncGuard.FindViolations(files);

        Assert.True(violations.Count == 0,
            "sync-over-async guard found deadlock patterns in the test suite (use async/await " +
            "instead of .Result/.GetAwaiter().GetResult()/.Wait(); do not suppress):\n" +
            string.Join("\n", violations.Select(v => $"{v.Path}:{v.Line}: {v.Snippet} — {v.Reason}")));
    }

    /// <summary>True when the path lives under a <c>bin</c> or <c>obj</c> build-output segment.</summary>
    private static bool IsBuildArtifact(string path)
    {
        var segments = path.Split(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
        return segments.Any(s => s is "bin" or "obj");
    }
}

